    // C: api_check(L, n >= 0, "negative 'n'");
    debug_assert!(n >= 0, "negative 'n'");
    let available = state.stack_available();
    let res = if available > n as usize {
        true
    } else {
        state.grow_stack(n, false).is_ok()
